/*
    "en-US-JennyNeural","en","美式女聲 (清晰)"
    "en-US-AnaNeural","en","美式女聲 (輕盈)"
    "en-GB-SoniaNeural","en","英式女聲"
    "zh-TW-HsiaoChenNeural","zh","台灣中文女聲"
    "zh-TW-YunJheNeural","zh","台灣中文男聲"
*/
const option = {
  userid: "Ken.liu", //使用者名稱
  voice: {
    en: { id: "en-US-JennyNeural", rate: "-50%" },
    zh: { id: "zh-TW-HsiaoChenNeural", rate: "+0%" },
  },
};

// 將 AI 生成的 ```Json ``` 移除, 變成 JSON
let rawOutput = $input.first().json.output;
let jsonObj = JSON.parse(
  rawOutput.replace(/^```json\s*/i, "").replace(/\s*```$/, ""),
);

const result = {
  meta: {
    userid: option.userid,
    voice: option.voice,
    rate: option.rate,
    model: jsonObj.meta.model,
  },
  items: jsonObj.items,
};
console.log(result);
return result;

// Merge Restore Items 與 TTS POST
const data = $input.first().json;

const mapVoice = {};
if (data.voices && Array.isArray(data.voices)) {
  data.voices.forEach((v) => {
    mapVoice[v.id] = {
      filename: v.filename,
      url: v.url,
    };
  });
}
const newItms = data.items.map((item) => {
  const newItem = item.content.map((con) => {
    return {
      ...con,
      filename: mapVoice[con.id].filename,
      url: mapVoice[con.id].url,
    };
  });
  return {
    type: item.type,
    content: newItem,
  };
});

return {
  meta: data.meta,
  items: newItms,
};
